@Component
public class AuthnRequestService {

    private final com.example.samlsp.config.SamlProperties props;
    private final IdpMetadataService idpMetadataService;
    private final SpKeyMaterialService spKeyMaterialService;

    public AuthnRequestService(com.example.samlsp.config.SamlProperties props,
                               IdpMetadataService idpMetadataService,
                               SpKeyMaterialService spKeyMaterialService) {
        this.props = props;
        this.idpMetadataService = idpMetadataService;
        this.spKeyMaterialService = spKeyMaterialService;
    }

    public BuiltAuthnRequest buildAuthnRequest(String relayState) {
        IDPSSODescriptor idp = idpMetadataService.resolveIdpSsoDescriptor();

        SingleSignOnService sso = idp.getSingleSignOnServices().stream()
                .filter(s -> SAMLConstants.SAML2_REDIRECT_BINDING_URI.equals(s.getBinding())
                        || SAMLConstants.SAML2_POST_BINDING_URI.equals(s.getBinding()))
                .min(Comparator.comparing(s -> SAMLConstants.SAML2_REDIRECT_BINDING_URI.equals(s.getBinding()) ? 0 : 1))
                .orElseThrow(() -> new IllegalStateException("No SSO service supporting Redirect or POST binding"));

        AuthnRequest req = (AuthnRequest) SamlBuilders.bf()
                .getBuilder(AuthnRequest.DEFAULT_ELEMENT_NAME).buildObject(AuthnRequest.DEFAULT_ELEMENT_NAME);
        req.setID("_" + UUID.randomUUID());
        req.setVersion(SAMLVersion.VERSION_20);
        req.setIssueInstant(new DateTime(Instant.now().toEpochMilli()));
        req.setDestination(sso.getLocation());
        req.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        req.setAssertionConsumerServiceURL(props.getAcsUrl());

        Issuer issuer = (Issuer) SamlBuilders.bf().getBuilder(Issuer.DEFAULT_ELEMENT_NAME).buildObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(props.getSpEntityId());
        req.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = (NameIDPolicy) SamlBuilders.bf()
                .getBuilder(NameIDPolicy.DEFAULT_ELEMENT_NAME).buildObject(NameIDPolicy.DEFAULT_ELEMENT_NAME);
        nameIDPolicy.setAllowCreate(true);
        nameIDPolicy.setFormat(props.getNameIdFormat());
        req.setNameIDPolicy(nameIDPolicy);

        if (props.isSignAuthnRequests()) {
            signSamlObject(req);
        }

        return new BuiltAuthnRequest(req, sso.getBinding(), sso.getLocation(), relayState);
    }

    private void signSamlObject(SignableSAMLObject signable) {
        try {
            Signature signature = (Signature) SamlBuilders.bf().getBuilder(Signature.DEFAULT_ELEMENT_NAME).buildObject(Signature.DEFAULT_ELEMENT_NAME);
            signature.setSigningCredential(spKeyMaterialService.getSigningCredential());
            signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
            signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

            var keyInfoGen = spKeyMaterialService.getKeyInfoGenerator();
            signature.setKeyInfo(keyInfoGen.generate(spKeyMaterialService.getSigningCredential()));

            signable.setSignature(signature);
            XMLObjectSupport.marshall(signable);
            Signer.signObject(signature);
        } catch (Exception e) {
            throw new IllegalStateException("Signing failed", e);
        }
    }

    public record BuiltAuthnRequest(AuthnRequest request, String binding, String destination, String relayState) {}
}
