@Component
public class SamlResponseValidator {

    private final com.example.samlsp.config.SamlProperties props;
    private final IdpMetadataService idpMetadataService;

    public SamlResponseValidator(com.example.samlsp.config.SamlProperties props, IdpMetadataService idpMetadataService) {
        this.props = props;
        this.idpMetadataService = idpMetadataService;
    }

    public SamlPrincipal validateAndExtractPrincipal(String base64Response) {
        try {
            byte[] decoded = Base64.getDecoder().decode(base64Response);
            Element element = XMLObjectProviderRegistrySupport.getParserPool()
                    .parse(new java.io.ByteArrayInputStream(decoded)).getDocumentElement();
            XMLObject xo = SamlXml.unmarshall(element);
            if (!(xo instanceof Response resp)) throw new IllegalStateException("Not a SAML Response");

            if (resp.getStatus() == null || resp.getStatus().getStatusCode() == null
                    || !StatusCode.SUCCESS.equals(resp.getStatus().getStatusCode().getValue())) {
                String code = resp.getStatus() != null && resp.getStatus().getStatusCode() != null ? resp.getStatus().getStatusCode().getValue() : "unknown";
                throw new IllegalStateException("SAML Response not successful: " + code);
            }

            List<X509Credential> idpCreds = resolveIdpSigningCredentials();

            if (props.isRequireSignedResponse()) {
                requireValidSignature(resp, idpCreds);
            }

            Assertion assertion = chooseAssertion(resp);
            if (props.isRequireSignedAssertion()) {
                requireValidSignature(assertion, idpCreds);
            } else if (assertion.isSigned()) {
                requireValidSignature(assertion, idpCreds);
            }

            validateConditions(assertion);
            String nameId = extractNameId(assertion);
            Map<String, List<String>> attrs = extractAttributes(assertion);

            return new SamlPrincipal(nameId, attrs, assertion.getID(), resp.getID());
        } catch (Exception e) {
            if (e instanceof IllegalStateException) throw (IllegalStateException) e;
            throw new IllegalStateException("SAML validation failed", e);
        }
    }

    private void requireValidSignature(SignableSAMLObject obj, List<X509Credential> idpCreds) {
        if (!obj.isSigned() || obj.getSignature() == null) {
            throw new IllegalStateException("Missing required signature on " + obj.getElementQName());
        }
        Exception last = null;
        for (X509Credential cred : idpCreds) {
            try {
                SignatureValidator.validate(obj.getSignature(), cred);
                return;
            } catch (Exception e) {
                last = e;
            }
        }
        throw new IllegalStateException("Invalid signature on " + obj.getElementQName(), last);
    }

    private List<X509Credential> resolveIdpSigningCredentials() {
        IDPSSODescriptor idp = idpMetadataService.resolveIdpSsoDescriptor();
        List<KeyDescriptor> kds = idp.getKeyDescriptors();
        List<X509Credential> creds = new ArrayList<>();
        for (KeyDescriptor kd : kds) {
            if (kd.getUse() != null && kd.getUse() != org.opensaml.saml.saml2.metadata.UsageType.SIGNING) continue;
            if (kd.getKeyInfo() == null) continue;
            try {
                List<X509Certificate> certs = KeyInfoSupport.getCertificates(kd.getKeyInfo());
                for (X509Certificate c : certs) {
                    creds.add(new BasicX509Credential(c));
                }
            } catch (Exception ignored) {}
        }
        if (creds.isEmpty()) throw new IllegalStateException("No IdP signing certificates found in metadata");
        return creds;
    }

    private Assertion chooseAssertion(Response resp) {
        if (resp.getAssertions() == null || resp.getAssertions().isEmpty()) {
            throw new IllegalStateException("No assertions in response");
        }
        return resp.getAssertions().getFirst();
    }

    private void validateConditions(Assertion assertion) {
        Conditions c = assertion.getConditions();
        if (c == null) return;

        Instant now = Instant.now();
        long skew = props.getClockSkewSeconds();

        if (c.getNotBefore() != null) {
            Instant nb = Instant.ofEpochMilli(c.getNotBefore().getMillis());
            if (now.isBefore(nb.minusSeconds(skew))) throw new IllegalStateException("Assertion not yet valid");
        }
        if (c.getNotOnOrAfter() != null) {
            Instant noa = Instant.ofEpochMilli(c.getNotOnOrAfter().getMillis());
            if (!now.isBefore(noa.plusSeconds(skew))) throw new IllegalStateException("Assertion expired");
        }

        List<AudienceRestriction> ars = c.getAudienceRestrictions();
        if (ars != null && !ars.isEmpty()) {
            boolean ok = ars.stream().flatMap(ar -> ar.getAudiences().stream())
                    .map(Audience::getURI)
                    .anyMatch(aud -> props.getSpEntityId().equals(aud));
            if (!ok) throw new IllegalStateException("Audience restriction failed");
        }
    }

    private String extractNameId(Assertion assertion) {
        Subject subj = assertion.getSubject();
        if (subj == null || subj.getNameID() == null || subj.getNameID().getValue() == null) {
            throw new IllegalStateException("Missing Subject/NameID");
        }
        return subj.getNameID().getValue();
    }

    private Map<String, List<String>> extractAttributes(Assertion assertion) {
        Map<String, List<String>> out = new LinkedHashMap<>();
        List<AttributeStatement> stmts = assertion.getAttributeStatements();
        if (stmts == null) return out;
        for (AttributeStatement st : stmts) {
            if (st.getAttributes() == null) continue;
            for (Attribute a : st.getAttributes()) {
                String name = a.getName();
                List<String> values = new ArrayList<>();
                if (a.getAttributeValues() != null) {
                    for (XMLObject v : a.getAttributeValues()) {
                        String text = v.getDOM() != null ? v.getDOM().getTextContent() : v.toString();
                        if (text != null) values.add(text);
                    }
                }
                out.put(name, values);
            }
        }
        return out;
    }

    public record SamlPrincipal(String nameId, Map<String, List<String>> attributes, String assertionId, String responseId) {}
}
package com.example.samlsp.web;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.saml.AuthnRequestService;
import com.example.samlsp.saml.SamlResponseValidator;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.opensaml.core.xml.util.XMLObjectSupport;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Controller;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.util.UriComponentsBuilder;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

@Controller
@RequestMapping("/saml")
public class SamlController {

    public static final String SESSION_PRINCIPAL = "SAML_PRINCIPAL";

    private final SamlProperties props;
    private final AuthnRequestService authnRequestService;
    private final SamlResponseValidator responseValidator;
    private final SamlMetadataController metadataController;

    public SamlController(SamlProperties props,
                          AuthnRequestService authnRequestService,
                          SamlResponseValidator responseValidator,
                          SamlMetadataController metadataController) {
        this.props = props;
        this.authnRequestService = authnRequestService;
        this.responseValidator = responseValidator;
        this.metadataController = metadataController;
    }

    @GetMapping("/login")
    public void login(@RequestParam(value = "relay", required = false) String relay,
                      HttpServletResponse response) throws IOException {
        String relayState = relay != null ? relay : props.getDefaultRedirect();
        var built = authnRequestService.buildAuthnRequest(relayState);

        String xml = XMLObjectSupport.prettyPrintXML(built.request().getDOM() != null ? built.request().getDOM() : com.example.samlsp.saml.SamlXml.marshall(built.request()));
        String samlRequest = Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));

        if (SAMLConstants.SAML2_POST_BINDING_URI.equals(built.binding())) {
            String html = "<html><body onload=\"document.forms[0].submit()\">"
                    + "<form method=\"post\" action=\"" + escapeHtml(built.destination()) + "\">"
                    + "<input type=\"hidden\" name=\"SAMLRequest\" value=\"" + escapeHtml(samlRequest) + "\"/>"
                    + "<input type=\"hidden\" name=\"RelayState\" value=\"" + escapeHtml(relayState) + "\"/>"
                    + "<noscript><input type=\"submit\" value=\"Continue\"/></noscript>"
                    + "</form></body></html>";
            response.setContentType(MediaType.TEXT_HTML_VALUE);
            response.getWriter().write(html);
            return;
        }

        String redirectUrl = UriComponentsBuilder.fromUriString(built.destination())
                .queryParam("SAMLRequest", urlEnc(samlRequest))
                .queryParam("RelayState", urlEnc(relayState))
                .build(true).toUriString();
        response.setStatus(302);
        response.setHeader(HttpHeaders.LOCATION, redirectUrl);
    }

    @PostMapping("/acs")
    public void acs(@RequestParam("SAMLResponse") String samlResponse,
                    @RequestParam(value = "RelayState", required = false) String relayState,
                    HttpServletRequest request,
                    HttpServletResponse response) throws IOException {
        var principal = responseValidator.validateAndExtractPrincipal(samlResponse);
        HttpSession session = request.getSession(true);
        session.setAttribute(SESSION_PRINCIPAL, principal);

        String target = (relayState != null && !relayState.isBlank()) ? relayState : props.getDefaultRedirect();
        response.setStatus(302);
        response.setHeader(HttpHeaders.LOCATION, target);
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        response.setStatus(302);
        response.setHeader(HttpHeaders.LOCATION, props.getDefaultRedirect());
    }

    @GetMapping("/me")
    @ResponseBody
    public Object me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return java.util.Map.of("authenticated", false);
        Object p = session.getAttribute(SESSION_PRINCIPAL);
        if (p == null) return java.util.Map.of("authenticated", false);
        return java.util.Map.of("authenticated", true, "principal", p);
    }

    private static String urlEnc(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }

    private static String escapeHtml(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\"", "&quot;").replace("'", "&#39;");
    }
}
package com.example.samlsp.web;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.saml.SpKeyMaterialService;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.util.XMLObjectSupport;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.metadata.*;
import org.opensaml.security.x509.X509Credential;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;

import java.security.cert.X509Certificate;
import java.util.UUID;

@Controller
public class SamlMetadataController {

    private final SamlProperties props;
    private final SpKeyMaterialService keys;

    public SamlMetadataController(SamlProperties props, SpKeyMaterialService keys) {
        this.props = props;
        this.keys = keys;
    }

    @GetMapping(value = "${saml.metadata-path:/saml/metadata}", produces = MediaType.APPLICATION_XML_VALUE)
    @ResponseBody
    public String metadata() {
        EntityDescriptor ed = buildSpMetadata();
        org.w3c.dom.Element dom = com.example.samlsp.saml.SamlXml.marshall(ed);
        return XMLObjectSupport.prettyPrintXML(dom);
    }

    private EntityDescriptor buildSpMetadata() {
        EntityDescriptor ed = (EntityDescriptor) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(EntityDescriptor.DEFAULT_ELEMENT_NAME).buildObject(EntityDescriptor.DEFAULT_ELEMENT_NAME);
        ed.setEntityID(props.getSpEntityId());
        ed.setID("_" + UUID.randomUUID());

        SPSSODescriptor sp = (SPSSODescriptor) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(SPSSODescriptor.DEFAULT_ELEMENT_NAME).buildObject(SPSSODescriptor.DEFAULT_ELEMENT_NAME);
        sp.addSupportedProtocol(SAMLConstants.SAML20P_NS);
        sp.setAuthnRequestsSigned(props.isSignAuthnRequests());
        sp.setWantAssertionsSigned(props.isRequireSignedAssertion());

        AssertionConsumerService acs = (AssertionConsumerService) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(AssertionConsumerService.DEFAULT_ELEMENT_NAME).buildObject(AssertionConsumerService.DEFAULT_ELEMENT_NAME);
        acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acs.setLocation(props.getAcsUrl());
        acs.setIndex(0);
        acs.setIsDefault(true);
        sp.getAssertionConsumerServices().add(acs);

        SingleLogoutService slo = (SingleLogoutService) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(SingleLogoutService.DEFAULT_ELEMENT_NAME).buildObject(SingleLogoutService.DEFAULT_ELEMENT_NAME);
        slo.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        slo.setLocation(props.getSloUrl());
        sp.getSingleLogoutServices().add(slo);

        KeyDescriptor kd = (KeyDescriptor) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(KeyDescriptor.DEFAULT_ELEMENT_NAME).buildObject(KeyDescriptor.DEFAULT_ELEMENT_NAME);
        kd.setUse(UsageType.SIGNING);

        KeyInfo ki;
        try {
            X509Credential cred = keys.getSigningCredential();
            ki = keys.getKeyInfoGenerator().generate(cred);
        } catch (Exception e) {
            throw new IllegalStateException("Failed generating KeyInfo", e);
        }
        kd.setKeyInfo(ki);
        sp.getKeyDescriptors().add(kd);

        NameIDFormat nif = (NameIDFormat) com.example.samlsp.saml.SamlBuilders.bf()
                .getBuilder(NameIDFormat.DEFAULT_ELEMENT_NAME).buildObject(NameIDFormat.DEFAULT_ELEMENT_NAME);
        nif.setURI(props.getNameIdFormat());
        sp.getNameIDFormats().add(nif);

        ed.getRoleDescriptors().add(sp);
        return ed;
    }
}
package com.example.samlsp.web;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.HttpHeaders;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Set;

@Component
public class SamlAuthFilter extends OncePerRequestFilter {

    private static final Set<String> PUBLIC_PATHS_PREFIX = Set.of(
            "/saml/login", "/saml/acs", "/saml/metadata", "/actuator", "/error"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (isPublic(path)) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        Object principal = session != null ? session.getAttribute(SamlController.SESSION_PRINCIPAL) : null;
        if (principal != null) {
            filterChain.doFilter(request, response);
            return;
        }

        String relay = request.getRequestURI();
        if (request.getQueryString() != null && !request.getQueryString().isBlank()) {
            relay = relay + "?" + request.getQueryString();
        }
        String url = "/saml/login?relay=" + URLEncoder.encode(relay, StandardCharsets.UTF_8);
        response.setStatus(302);
        response.setHeader(HttpHeaders.LOCATION, url);
    }

    private boolean isPublic(String path) {
        for (String p : PUBLIC_PATHS_PREFIX) {
            if (path.equals(p) || path.startsWith(p + "/")) return true;
        }
        return false;
    }
}
package com.example.samlsp.config;

import com.example.samlsp.web.SamlAuthFilter;
import org.springframework.boot.web.servlet.FilterRegistrationBean;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class WebConfig {

    @Bean
    public FilterRegistrationBean<SamlAuthFilter> samlAuthFilterRegistration(SamlAuthFilter filter) {
        FilterRegistrationBean<SamlAuthFilter> reg = new FilterRegistrationBean<>();
        reg.setFilter(filter);
        reg.addUrlPatterns("/*");
        reg.setOrder(1);
        return reg;
    }
}
